5	/* Prevent native browser text/element drag from hijacking pointer events.
6	   Without this, clicking SVG text elements and dragging fires dragstart,
7	   which cancels pointerdown capture and leaves marquee/selection state broken.
8	   user-select is still honoured inside <input>/<textarea> by browsers. */
9	body {
10	  user-select: none;
11	}
