575	  /* Typography */
576	  --io-text-4xl: 2.25rem;
577	  --io-text-3xl: 1.75rem;
578	  --io-text-2xl: 1.375rem;
579	  --io-text-xl: 1.125rem;
580	  --io-text-lg: 1rem;
581	  --io-text-base: 0.875rem;
582	  --io-text-sm: 0.8125rem;
583	  --io-text-xs: 0.75rem;
584	  --io-text-2xs: 0.6875rem;
585	  --io-text-label: 0.75rem;
586	  --io-text-label-sm: 0.6875rem;
587	  --io-text-value: 0.875rem;
588	  --io-text-value-lg: 1.125rem;
589	  --io-text-value-xl: 1.5rem;
590	  --io-text-code: 0.8125rem;
591	  --io-text-code-sm: 0.75rem;
