611	}
612	
613	/* ============================================================
614	   Alarm State CSS Classes (doc 38 / doc 35)
615	   Applied to display elements, not theme-dependent.
616	   ============================================================ */
617	
618	/* Skeleton loading pulse */
619	@keyframes io-pulse {
620	  0%,
621	  100% {
622	    opacity: 1;
623	  }
624	  50% {
625	    opacity: 0.45;
626	  }
627	}
628	
629	/* Skeleton shimmer — module-shaped loading states */
630	@keyframes io-shimmer {
631	  0% {
632	    background-position: 200% 0;
633	  }
634	  100% {
635	    background-position: -200% 0;
636	  }
637	}
638	
639	.io-skeleton {
640	  background: linear-gradient(
641	    90deg,
642	    var(--io-surface-secondary) 25%,
643	    var(--io-surface-elevated) 50%,
644	    var(--io-surface-secondary) 75%
645	  );
646	  background-size: 200% 100%;
647	  animation: io-shimmer 1.5s linear infinite;
648	}
649	
650	/* Unacknowledged — 1Hz flash between alarm color and gray */
651	@keyframes io-alarm-flash {
652	  0%,
653	  49% {
654	    opacity: 1;
655	  }
656	  50%,
657	  100% {
658	    opacity: 0.25;
659	  }
660	}
661	
662	.io-unack {
663	  animation: io-alarm-flash 1s step-end infinite;
664	}
665	.io-ack {
666	  /* Steady alarm color — no animation */
667	}
668	.io-rtn-unack {
669	  opacity: 0.6;
670	}
671	.io-shelved {
672	  border-style: dashed !important;
673	  opacity: 0.7;
674	}
675	.io-suppressed {
676	  opacity: 0.4;
677	}
678	.io-oos-display {
679	  text-decoration: line-through;
680	  opacity: 0.5;
681	}
682	
683	/* Data Quality CSS Classes */
684	.io-quality-stale {
685	  outline: 1px dashed var(--io-border-strong);
686	  opacity: 0.6;
687	}
688	.io-quality-bad {
689	  outline: 1px dashed var(--io-alarm-urgent);
690	}
691	.io-quality-comm-fail {
692	  outline: 1px solid var(--io-alarm-disabled);
693	  opacity: 0.7;
694	}
695	.io-quality-uncertain {
696	  outline: 1px dotted var(--io-border-strong);
697	}
698	.io-quality-manual {
699	  outline: 1px solid var(--io-alarm-diagnostic);
700	}
701	
702	/* ============================================================
703	   Context Menu Animations
704	   ============================================================ */
705	
706	@keyframes io-context-menu-in {
707	  from {
708	    opacity: 0;
709	    transform: scale(0.97) translateY(-3px);
710	  }
711	  to {
712	    opacity: 1;
713	    transform: scale(1) translateY(0);
714	  }
715	}
716	
717	@keyframes io-dropdown-in {
718	  from {
719	    opacity: 0;
720	    transform: scale(0.96) translateY(-4px);
721	  }
722	  to {
723	    opacity: 1;
724	    transform: scale(1) translateY(0);
725	  }
726	}
727	
728	/* ============================================================
729	   Base resets
730	   ============================================================ */
731	
732	* {
733	  box-sizing: border-box;
734	}
735	
736	html,
737	body,
738	#root {
739	  height: 100%;
740	  margin: 0;
741	}
742	
743	body {
744	  margin: 0;
745	  background: var(--io-surface-primary);
746	  color: var(--io-text-primary);
747	  font-family:
748	    "InterVariable",
749	    "Inter",
750	    -apple-system,
751	    BlinkMacSystemFont,
752	    "Segoe UI",
753	    Roboto,
754	    "Helvetica Neue",
755	    sans-serif;
756	  font-size: var(--io-text-base, 0.875rem);
757	  line-height: 1.5;
758	  -webkit-font-smoothing: antialiased;
759	  -moz-osx-font-smoothing: grayscale;
760	}
761	
762	/* Monospace for code/data contexts */
763	code,
764	pre,
765	kbd,
766	.io-mono {
767	  font-family:
768	    "JetBrains Mono Variable", "JetBrains Mono", "Fira Code", "Courier New",
769	    monospace;
770	  font-size: var(--io-text-code, 0.8125rem);
771	}
772	
773	/* Tabular numbers for data values — prevents layout jitter */
774	.io-tabular {
775	  font-variant-numeric: tabular-nums;
776	}
777	
778	/* ============================================================
779	   Scrollbar styling
780	   ============================================================ */
781	
782	::-webkit-scrollbar {
783	  width: 6px;
784	  height: 6px;
785	}
786	
787	::-webkit-scrollbar-track {
788	  background: transparent;
789	}
790	
791	::-webkit-scrollbar-thumb {
792	  background: var(--io-border);
793	  border-radius: 3px;
794	}
795	
796	::-webkit-scrollbar-thumb:hover {
797	  background: var(--io-text-muted);
798	}
799	
800	/* ============================================================
801	   Focus ring
802	   ============================================================ */
803	
804	:focus-visible {
805	  outline: 2px solid var(--io-focus-ring, var(--io-accent));
806	  outline-offset: 2px;
807	}
808	
809	/* ============================================================
810	   Text selection
811	   ============================================================ */
812	
813	::selection {
814	  background: var(--io-accent-subtle);
815	  color: var(--io-text-primary);
816	}
817	
818	/* ============================================================
819	   Mobile touch targets — gloved operation (doc 20 §Touch Targets)
820	   60px minimum for standard controls; 72px for critical actions.
821	   Applies only on coarse-pointer (touch) devices.
822	   ============================================================ */
823	
824	@media (pointer: coarse) {
825	  /* Standard interactive elements — 60px minimum */
826	  button,
827	  [role="button"],
828	  a,
829	  input[type="checkbox"],
830	  input[type="radio"],
831	  select,
832	  .io-tab,
833	  .io-nav-item,
834	  .io-list-item {
835	    min-height: 60px;
836	    min-width: 60px;
837	  }
838	
839	  /* Icon-only buttons expand their hit area via padding */
840	  button.io-icon-btn {
841	    min-height: 60px;
842	    min-width: 60px;
843	    padding: 12px;
844	  }
845	
846	  /* Critical actions (alarm ack, emergency, submit) — 72px minimum */
847	  .io-critical-action,
848	  button[data-critical="true"],
849	  [role="button"][data-critical="true"] {
850	    min-height: 72px;
851	    min-width: 72px;
852	  }
853	
854	  /* Form inputs — taller tap zone */
855	  input[type="text"],
856	  input[type="number"],
857	  input[type="email"],
858	  input[type="password"],
859	  textarea {
860	    min-height: 60px;
861	  }
862	}
863	
864	/* ============================================================
865	   Print stylesheet — color normalization (doc 06)
866	   ============================================================ */
867	
868	@media print {
869	  :root {
870	    --io-surface-primary: #ffffff;
871	    --io-surface-secondary: #f9fafb;
872	    --io-surface-elevated: #ffffff;
873	    --io-surface: #ffffff;
874	    --io-text-primary: #111827;
875	    --io-text-secondary: #374151;
876	    --io-text-muted: #6b7280;
877	    --io-border: #d1d5db;
878	    /* Alarm colors preserved (semantic meaning must survive print) */
879	  }
880	
881	  body {
882	    background: #ffffff;
883	    color: #111827;
884	  }
885	
886	  /* Hide navigation chrome */
887	  .io-sidebar,
888	  .io-topbar,
889	  .io-toolbar,
890	  [role="navigation"] {
891	    display: none !important;
892	  }
893	}
894	
895	/* Canonical Mode A (view) node selection glow — docs/decisions/selection-behavior.md */
896	[data-node-id].io-node-selected {
897	  filter: drop-shadow(
898	      0 0 3px color-mix(in srgb, var(--io-accent) 80%, transparent)
899	    )
900	    drop-shadow(0 0 6px color-mix(in srgb, var(--io-accent) 40%, transparent));
901	}
902	
903	/* Designer Mode B multi-select: glow on actual shape geometry, not an overlay rect */
904	svg.io-multiselect-active [data-node-id].io-selected {
905	  filter: drop-shadow(
906	      0 0 3px color-mix(in srgb, var(--io-accent) 80%, transparent)
907	    )
908	    drop-shadow(0 0 6px color-mix(in srgb, var(--io-accent) 40%, transparent));
909	}
